import React, { useState } from 'react';
import { Reveal } from "../components/AboutUs/Reveal";
import SideNav from "../components/AboutUs/SideNav";
import MobileTopNav from "../components/AboutUs/MobileTopNav";

// Estilos de fuentes integrados directamente
const fontStyles = `
  @font-face {
    font-family: 'BodoniStd';
    src: url('/forts/As_BodoniStd.off') format('opentype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  @font-face {
    font-family: 'TrajanPro';
    src: url('/forts/As_TrajanProRegular.tif') format('truetype');
    font-weight: normal;
    font-style: normal;
    font-display: swap;
  }

  .font-bodoni {
    font-family: 'BodoniStd', serif;
    letter-spacing: -0.02em;
  }

  .font-trajan {
    font-family: 'TrajanPro', serif;
    letter-spacing: 0.01em;
  }
`;

// Insertar estilos en el head del documento
if (typeof document !== 'undefined') {
  const styleElement = document.createElement('style');
  styleElement.textContent = fontStyles;
  document.head.appendChild(styleElement);
}

const EquipoPage = () => {
  const [activeCategory, setActiveCategory] = useState('delegacion');
  
  const sections = [
    { id: 'delegacion', label: 'Delegación' },
    { id: 'backend', label: 'Backend' },
    { id: 'frontend', label: 'Frontend' },
    { id: 'basedatos', label: 'Base de Datos' },
    { id: 'dashboard', label: 'Dashboard' }
  ];

  // Datos de ejemplo del equipo
  const teamMembers = {
    delegacion: [
      { id: 1, name: 'Ana Rodríguez', position: 'Project Manager', photo: '👩‍💼', skills: ['Liderazgo', 'Estrategia', 'Gestión'] },
      { id: 2, name: 'Carlos Méndez', position: 'Líder de Equipo', photo: '👨‍💼', skills: ['Coordinación', 'Planificación', 'Mentoría'] },
      { id: 3, name: 'María Fernández', position: 'Coordinadora', photo: '👩‍💻', skills: ['Organización', 'Comunicación', 'Logística'] }
    ],
    backend: [
      { id: 1, name: 'Javier López', position: 'Senior Backend Dev', photo: '👨‍💻', skills: ['Node.js', 'Python', 'APIs'] },
      { id: 2, name: 'Laura Martínez', position: 'API Specialist', photo: '👩‍🔧', skills: ['REST', 'GraphQL', 'Microservicios'] },
      { id: 3, name: 'Diego Ramírez', position: 'DevOps Engineer', photo: '👨‍🔬', skills: ['AWS', 'Docker', 'CI/CD'] }
    ],
    frontend: [
      { id: 1, name: 'Sofía García', position: 'Frontend Lead', photo: '👩‍🎨', skills: ['React', 'TypeScript', 'UX'] },
      { id: 2, name: 'Miguel Ángel Torres', position: 'UI/UX Developer', photo: '👨‍🎨', skills: ['Figma', 'Prototipado', 'Design Systems'] },
      { id: 3, name: 'Elena Vargas', position: 'React Specialist', photo: '👩‍💻', skills: ['Hooks', 'Context', 'Performance'] }
    ],
    basedatos: [
      { id: 1, name: 'Roberto Silva', position: 'Database Architect', photo: '👨‍🔧', skills: ['SQL', 'MongoDB', 'Optimización'] },
      { id: 2, name: 'Carolina Ríos', position: 'Data Analyst', photo: '👩‍🔬', skills: ['ETL', 'Power BI', 'Estadística'] },
      { id: 3, name: 'Andrés Castillo', position: 'DB Administrator', photo: '👨‍💼', skills: ['Seguridad', 'Backups', 'Monitorización'] }
    ],
    dashboard: [
      { id: 1, name: 'Patricia Navarro', position: 'Dashboard Designer', photo: '👩‍💼', skills: ['DataViz', 'Tableau', 'Storytelling'] },
      { id: 2, name: 'Fernando Jiménez', position: 'Data Visualization', photo: '👨‍🎨', skills: ['D3.js', 'Chart.js', 'Animaciones'] },
      { id: 3, name: 'Gabriela Ortega', position: 'Analytics Specialist', photo: '👩‍🔧', skills: ['KPIs', 'Métricas', 'Business Intelligence'] }
    ]
  };

  return (
    <div className="min-h-screen bg-white">
      <SideNav sections={sections} />
      <MobileTopNav sections={sections} />

      <div className="md:flex">
        {/* Left reserved column to avoid overlap with fixed sidenav */}
        <aside className="hidden md:block md:w-[18%] lg:w-[17%] xl:w-[15%] shrink-0" aria-hidden />

        {/* Right content column */}
        <div className="md:w-[82%] lg:w-[83%] xl:w-[85%] md:ml-auto">
          {/* Header Section */}
          <section className="relative scroll-mt-24">
            <div className="container mx-auto px-6 py-20">
              <Reveal>
                <div className="text-center max-w-3xl mx-auto">
                  <p className="uppercase tracking-[0.2em] text-xs text-[#072D42]/60 font-medium font-trajan mb-4">
                    Nuestro Equipo
                  </p>
                  <h1 className="font-bodoni text-4xl md:text-5xl text-[#072D42] mb-6 leading-[1.1]">
                    Talento y <span className="text-[#F29E38]">Dedicación</span>
                  </h1>
                  <div className="w-16 h-0.5 bg-[#F29E38] mx-auto mb-8"></div>
                  <p className="text-[#072D42]/80 text-lg leading-relaxed font-trajan">
                    Conoce al equipo profesional detrás de Orbis Empresarial. 
                    Expertos comprometidos con la excelencia y la innovación.
                  </p>
                </div>
              </Reveal>
            </div>
          </section>

          {/* Team Sections */}
          {sections.map((section, index) => (
            <section 
              key={section.id} 
              id={section.id} 
              className="relative scroll-mt-24 border-t border-[#072D42]/5"
            >
              <div className="container mx-auto px-6 py-16">
                <Reveal delay={index * 100}>
                  <div className="mb-12 text-center">
                    <h2 className="font-bodoni text-3xl text-[#072D42] mb-4">
                      {section.label}
                    </h2>
                    <div className="w-12 h-0.5 bg-[#F29E38] mx-auto"></div>
                  </div>
                </Reveal>

                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 max-w-6xl mx-auto">
                  {teamMembers[section.id].map((member, memberIndex) => (
                    <Reveal key={member.id} delay={(index * 100) + (memberIndex * 50)}>
                      <div className="bg-white rounded-lg border border-[#072D42]/10 hover:shadow-md transition-all duration-300 group overflow-hidden flex flex-col md:flex-row md:h-40">
                        {/* Photo/Icon Section */}
                        <div className="md:w-1/3 flex items-center justify-center p-4 bg-[#F4E9D7] group-hover:bg-[#072D42] transition-colors duration-300">
                          <div className="text-4xl group-hover:text-white transition-colors duration-300">
                            {member.photo}
                          </div>
                        </div>
                        
                        {/* Content Section */}
                        <div className="md:w-2/3 p-4 flex flex-col justify-between">
                          <div>
                            <h3 className="font-bodoni text-xl text-[#072D42] mb-1">
                              {member.name}
                            </h3>
                            <p className="text-[#072D42]/70 text-sm font-trajan mb-3">
                              {member.position}
                            </p>
                          </div>
                          
                          <div className="flex flex-wrap gap-1">
                            {member.skills.map((skill, skillIndex) => (
                              <span 
                                key={skillIndex}
                                className="inline-flex items-center px-2 py-1 bg-[#F4E9D7]/50 text-[#072D42] text-xs rounded-full font-trajan"
                              >
                                {skill}
                              </span>
                            ))}
                          </div>
                        </div>
                      </div>
                    </Reveal>
                  ))}
                </div>
              </div>
            </section>
          ))}

          {/* Call to Action Section */}
          <section className="relative bg-[#072D42] scroll-mt-24">
            <div className="container mx-auto px-6 py-20">
              <Reveal>
                <div className="text-center max-w-2xl mx-auto">
                  <h2 className="font-bodoni text-3xl text-white mb-6">
                    Únete a Nuestro Equipo
                  </h2>
